async function main() {
    // First, delete all existing districts
    console.log("🗑️  Deleting existing districts...");
    const deleted = await prisma_1.prisma.district.deleteMany();
    console.log(`🗑️  Deleted ${deleted.count} existing districts`);
    // Get all provinces to map codes to IDs
    const provinces = await prisma_1.prisma.province.findMany({
        select: { id: true, code: true },
    });
    const provinceMap = new Map(provinces.map((p) => [p.code, p.id]));
    // Map districts and validate province codes
    const districtsToInsert = districts
        .map((district) => {
        const provinceId = provinceMap.get(district.provinceCode);
        if (!provinceId) {
            console.error(`❌ Province code ${district.provinceCode} not found for district ${district.code}`);
            return null;
        }
        // Combine provinceCode + districtCode to create unique code (e.g. "0101")
        const uniqueCode = `${district.provinceCode}${district.code}`;
        return {
            code: uniqueCode,
            nameLo: district.nameLo,
            nameEn: district.nameEn,
            provinceCode: district.provinceCode,
            createdBy: district.createdBy,
        };
    })
        .filter((district) => district !== null);
    // Insert all districts in one operation
    const result = await prisma_1.prisma.district.createMany({
        data: districtsToInsert,
        skipDuplicates: true,
    });
    console.log(`\n✅ Successfully inserted ${result.count} districts`);
    if (result.count < districtsToInsert.length) {
        console.log(`⚠️  ${districtsToInsert.length - result.count} districts were skipped (duplicates)`);
    }
}
main()
    .catch((e) => {
    console.error(e);
    process.exit(1);
})
    .finally(async () => {
    await prisma_1.prisma.$disconnect();
});
